appsmith.onReady(() => {
  appsmith.onModelChange(model => {
    const rawData = model.cookies || {};
    const components = rawData.components || {};
    const summary = components.summary || {};
    const byType = summary.by_type || {};
    const detections = components.detections || [];

    // =====================================================================
    // CONFIG — presentation only (no data source for these in the scan).
    //   - badgeByType: CSS color class per detection type (cosmetic).
    //   - emptyTable:  empty-state label text.
    // The Signal Type text itself is the REAL det.type, not an invented label.
    // =====================================================================
    const CONFIG = {
      badgeByType: {
        model_artifact: 'badge-critical',
        llm_sdk: 'badge-warning',
        llm_framework: 'badge-warning',
        agent: 'badge-warning',
        rag: 'badge-warning'
      },
      badgeDefault: 'badge-exposure',
      // Inline box style applied to specific signal types (cosmetic).
      // ml_framework gets a light-blue box surrounding the text.
      boxStyleByType: {
        ml_framework: 'border:1px solid #5dade2;background:#eaf4fb;color:#1b4f72;border-radius:3px;'
      },
      emptyTable: 'No AI exposure signals detected.'
    };

    // Format a snake_case type into a label: model_artifact -> "Model Artifact",
    // llm_sdk -> "LLM SDK", ml_framework -> "ML Framework", vector_db -> "Vector DB".
    const fmtType = t => String(t || '').split('_').map(w => w.length <= 3 ? w.toUpperCase() : w.charAt(0).toUpperCase() + w.slice(1)).join(' ');

    // --- 1. Executive KPI cards (wired to the scan) ---------------------
    const frameworkCount = (byType.llm_framework?.count || 0) + (byType.agent?.count || 0);
    const llmCallCount = byType.llm_sdk?.count || 0;
    const ragCount = byType.rag?.count || 0;
    const artifactCount = byType.model_artifact?.count || 0;
    document.getElementById('stat-frameworks').innerText = frameworkCount;
    document.getElementById('stat-llm').innerText = llmCallCount;
    document.getElementById('stat-rag').innerText = ragCount;
    document.getElementById('stat-artifacts').innerText = artifactCount;

    // --- 2. Exposure & Policy Drift Log (one row per detection) ----------
    const tbody = document.getElementById('risk-table-body');
    tbody.innerHTML = '';
    if (detections.length === 0) {
      tbody.innerHTML = `<tr><td colspan="4" style="text-align: center;">${CONFIG.emptyTable}</td></tr>`;
      return;
    }
    detections.forEach(det => {
      const tr = document.createElement('tr');

      // AI Component name
      const tdComp = document.createElement('td');
      const code = document.createElement('code');
      code.textContent = det.name || '';
      tdComp.appendChild(code);

      // Provider / Context — real provider, falling back to the formatted type
      const tdProvider = document.createElement('td');
      tdProvider.textContent = det.provider || fmtType(det.type);

      // Exposure Signal Type — the REAL detection type from the scan
      const tdSignal = document.createElement('td');
      const signalBadge = document.createElement('span');
      const badgeClass = CONFIG.badgeByType[det.type] || CONFIG.badgeDefault;
      signalBadge.className = `badge ${badgeClass}`;
      signalBadge.textContent = fmtType(det.type);
      // Optional box style around the text (e.g. light-blue box for ML Framework)
      const boxStyle = CONFIG.boxStyleByType[det.type];
      if (boxStyle) {
        signalBadge.style.cssText = boxStyle;
      }
      tdSignal.appendChild(signalBadge);

      // Evidence pointer — real file (and line when present)
      const tdEvidence = document.createElement('td');
      tdEvidence.className = 'evidence';
      tdEvidence.textContent = `${det.file || ''}${det.line > 0 ? ' : L' + det.line : ''}`;
      tr.appendChild(tdComp);
      tr.appendChild(tdProvider);
      tr.appendChild(tdSignal);
      tr.appendChild(tdEvidence);
      tbody.appendChild(tr);
    });
  });
});

